// // This module implements an 8-bit shift register that shifts right on each positive edge of the clock signal and does not load new data when the load signal is high.
module ShiftRegister8Bit (
    input clk,
    input reset,
    input load,
    input [7:0] data,
    output reg [7:0] q
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 8'b00000000;
        else if (load)
            q <= data;
        else
            q <= q << 1;
    end
endmodule
